import java.util.List;

class Solution {
    public int trap(List<Integer> height) {
        // Write your code here
        int left = 0, right = height.size() - 1;
        int leftMax = 0, rightMax = 0, water = 0;
        while (left < right) {
            if (height.get(left) < height.get(right)) {
                if (height.get(left) >= leftMax) leftMax = height.get(left);
                else water += leftMax - height.get(left);
                left++;
            } else {
                if (height.get(right) >= rightMax) rightMax = height.get(right);
                else water += rightMax - height.get(right);
                right--;
            }
        }
        return water;
    }
}

